-- schema_v34_risk_library.sql
-- V34: Global industry risk library and control reference library.
-- These tables are NOT scoped to a company — they are shared reference data.

-- Risk Library
CREATE TABLE IF NOT EXISTS risk_library (
    id               SERIAL PRIMARY KEY,
    pillar           VARCHAR(50)  NOT NULL,
    sector           VARCHAR(100) NOT NULL,
    risk_detail      TEXT         NOT NULL,
    typical_cause    TEXT,
    typical_impact   TEXT,
    treatment_strategy TEXT,
    created_at       TIMESTAMPTZ  DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_risk_library_pillar ON risk_library (pillar);
CREATE INDEX IF NOT EXISTS idx_risk_library_sector ON risk_library (sector);

-- Control Reference Library
CREATE TABLE IF NOT EXISTS control_library (
    id                  SERIAL PRIMARY KEY,
    name                VARCHAR(255) NOT NULL,
    description         TEXT,
    control_type        VARCHAR(50),
    automation          VARCHAR(50),
    framework_reference TEXT,
    testing_frequency   VARCHAR(100),
    created_at          TIMESTAMPTZ  DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_control_library_type ON control_library (control_type);

-- Seed: Risk Library

